package operators;

public class Relaltionalopertors {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a=5;
		int b=3;
		//relational operators are used to compare two values and it return boolean values as result
		//<,>,<=,>=,==,!=
		System.out.println(a==b);
		System.out.println(a!=b);
		System.out.println(a<b);
		System.out.println(a>b);
		System.out.println(a<=b);
		System.out.println(a>=b);

	}

}
